#include <bits/stdc++.h>
using namespace std;

bool canDivide(vector<int>& sweetness, int k, int minSweet) {
    int count = 0;
    int currentSum = 0;

    for(int s : sweetness) {
        currentSum += s;
        if(currentSum >= minSweet) {
            count++;
            currentSum = 0;
        }
    }
    return count >= k + 1;
}

int maxMinSweetness(vector<int>& sweetness, int k) {
    int left = 1;
    int right = accumulate(sweetness.begin(), sweetness.end(), 0);
    int result = 0;

    while(left <= right) {
        int mid = left + (right - left) / 2;
        if(canDivide(sweetness, k, mid)) {
            result = mid;
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }
    return result;
}

int main() {
    int t;
    cin >> t;

    while(t--) {
        int n, k;
        cin >> n >> k;

        vector<int> sweetness(n);
        for(int i = 0; i < n; i++) {
            cin >> sweetness[i];
        }

        cout << maxMinSweetness(sweetness, k) << endl;
    }
    return 0;
}
